// HQ posts { id, action: 'approve'|'pass', pod, title, amount } here when you tap a button.
// THIS is where real executor actions belong, per pod, e.g.:
//   pod 'Fiverr Studio' + approve  -> mark order ready, you deliver in the Fiverr UI
//   pod 'Gov War Room'  + approve  -> send the RFQ emails via Gmail node
// Until an executor is wired, we just confirm on Telegram — a safe default.
const b = $json.body || $json;
const icon = b.action === 'approve' ? '✅' : '⏭️';
return [{ json: { ...b, text: icon + ' ' + (b.action === 'approve' ? 'Approved' : 'Passed') + ': ' + b.title + (b.amount ? ' (+$' + b.amount + ')' : '') + '\npod: ' + (b.pod || '?') } }];
